    edge(int _v, ll _w1, ll _w2) : v(_v), w{_w1, _w2} {}

};

vector<edge> g[MAXN];

ll dist[2][MAXN];

bool inq[MAXN];

void spfa(int s, int ty) {

    queue<int> q;

    memset(dist[ty], 0x3f, sizeof(dist[ty]));

    dist[ty][s] = 0;

    q.push(s);

    inq[s] = true;

    while (!q.empty()) {

