        q.pop();

        inq[u] = false;

        for (auto &e : g[u]) {

            int v = e.v;

            ll w = e.w[ty];

            if (dist[ty][v] > dist[ty][u] + w) {

                dist[ty][v] = dist[ty][u] + w;

                if (!inq[v]) {

                    q.push(v);

