                int we = p[i % n - 1];

                for (int mask = 0; mask < (1 << (n - 1)); mask++) {

                    if (!(mask >> we & 1)) {

                        for (int ac = i; ac <= c; ac++) {

                            dp[max(ac, min(c, L[we] + i))][mask | (1 << we)] += dp[ac][mask];

